#!/usr/bin/env node
/* Task #5 generator — 9 new fiscalidad 2026 articles × 6 languages.
 * Writes content files, updates BLOG_POSTS, blog-i18n/{lang}.ts and blog-posts-slugs.ts.
 */
import { readFileSync, writeFileSync, mkdirSync, existsSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, "..");
const CONTENT = resolve(ROOT, "client/src/data/blog-content");
const LANGS = ["es", "en", "fr", "de", "pt", "ca"];
const TODAY = "2026-04-21";

const BOOK = { es: "/es/agendar", en: "/en/book", fr: "/fr/reserver", de: "/de/buchen", pt: "/pt/agendar", ca: "/ca/agendar" };
const CALC = { es: "/es#calculadora", en: "/en#calculadora", fr: "/fr#calculadora", de: "/de#calculadora", pt: "/pt#calculadora", ca: "/ca#calculadora" };
const BOOK_LABEL = { es: "agenda una consulta gratuita", en: "book a free consultation", fr: "reserve une consultation gratuite", de: "buche eine kostenlose Beratung", pt: "agenda uma consulta gratuita", ca: "agenda una consulta gratuïta" };
const CALC_LABEL = { es: "calculadora fiscal Exentax", en: "Exentax tax calculator", fr: "calculatrice fiscale Exentax", de: "Exentax Steuerrechner", pt: "calculadora fiscal Exentax", ca: "calculadora fiscal Exentax" };
const CTA_INTRO = {
  es: (slug) => `> ¿Quieres ver tu caso con tus propios números? Modela tu situación en la <a href="${CALC.es}">${CALC_LABEL.es}</a> antes de tomar una decisión.`,
  en: (slug) => `> Want to model your case with your own numbers? Run your situation through the <a href="${CALC.en}">${CALC_LABEL.en}</a> before making a decision.`,
  fr: (slug) => `> Vous voulez modéliser votre cas avec vos propres chiffres ? Utilisez la <a href="${CALC.fr}">${CALC_LABEL.fr}</a> avant de décider.`,
  de: (slug) => `> Möchten Sie Ihren Fall mit eigenen Zahlen durchspielen? Nutzen Sie den <a href="${CALC.de}">${CALC_LABEL.de}</a>, bevor Sie entscheiden.`,
  pt: (slug) => `> Quer modelar o seu caso com os seus próprios números? Use a <a href="${CALC.pt}">${CALC_LABEL.pt}</a> antes de decidir.`,
  ca: (slug) => `> Vols modelar el teu cas amb els teus propis números? Fes servir la <a href="${CALC.ca}">${CALC_LABEL.ca}</a> abans de decidir.`,
};
const CTA_END = {
  es: `En Exentax revisamos tu caso con datos reales y te decimos si compensa cambiar de estructura. <a href="${BOOK.es}">${BOOK_LABEL.es}</a> de 30 minutos y salimos con un plan claro.`,
  en: `At Exentax we review your case with real data and tell you whether changing structure pays off. <a href="${BOOK.en}">${BOOK_LABEL.en}</a> of 30 minutes and you leave with a clear plan.`,
  fr: `Chez Exentax nous étudions votre cas avec des données réelles et vous disons si changer de structure est rentable. <a href="${BOOK.fr}">${BOOK_LABEL.fr}</a> de 30 minutes et vous repartez avec un plan clair.`,
  de: `Bei Exentax prüfen wir Ihren Fall mit echten Daten und sagen Ihnen, ob sich ein Strukturwechsel lohnt. <a href="${BOOK.de}">${BOOK_LABEL.de}</a> von 30 Minuten, und Sie gehen mit einem klaren Plan.`,
  pt: `Na Exentax analisamos o teu caso com dados reais e dizemos-te se compensa mudar de estrutura. <a href="${BOOK.pt}">${BOOK_LABEL.pt}</a> de 30 minutos e sais com um plano claro.`,
  ca: `A Exentax revisem el teu cas amb dades reals i et diem si compensa canviar d'estructura. <a href="${BOOK.ca}">${BOOK_LABEL.ca}</a> de 30 minuts i surts amb un pla clar.`,
};

function buildBody(intro, sections, closing, lang, slug) {
  const parts = [intro, "", CTA_INTRO[lang](slug), ""];
  for (const [h2, body] of sections) {
    parts.push(`## ${h2}`, "", body, "");
  }
  parts.push(closing, "", CTA_END[lang]);
  return parts.join("\n");
}

